+
+    // ── Error source chain ──────────────────────────────────────────────
+
+    #[test]
+    fn io_error_source_preserved() {
+        use std::error::Error;
+        let io_err = std::io::Error::new(std::io::ErrorKind::PermissionDenied, "no access");
