+    #[test]
+    fn test_overlapping_pools_dedup() {
+        // Two pools of 10 docs each, 3 overlapping (docs 5, 6, 7)
+        let lexical: Vec<_> = (1..=10)
+            .map(|i| CandidateHit::new(i, 1.0 - i as f64 * 0.1))
+            .collect();
+        let semantic: Vec<_> = (5..=14)
